                        mergedDuplicateTurnMemories: Number(reconcileResult?.mergedDuplicateTurnMemories || 0),
                        mergedNarrativeTurns: Number(reconcileResult?.mergedNarrativeTurns || 0),
                        reorderedTurns: Number(reconcileResult?.reorderedTurns || 0),
