                scannedMessages: report.scannedMessages,
                touchedEntities: report.touchedEntities,
                touchedRelations: report.touchedRelations,
                updatedEntities: report.updatedEntities,
                updatedRelations: report.updatedRelations,
                createdEntities: report.createdEntities,
                droppedRelations: report.droppedRelations,
                discardedEntries: report.discardedEntries,
                parseErrorCount: report.parseErrorCount,
                schemaMismatchCount: report.schemaMismatchCount,
                totalFixes: report.totalFixes,
                worldSummaryTouched: report.worldSummaryTouched,
                mergedDuplicateTurnMemories: report.mergedDuplicateTurnMemories,
                mergedNarrativeTurns: report.mergedNarrativeTurns,
                reorderedTurns: report.reorderedTurns,
                staticBootstrapChecked: report.staticBootstrapChecked,
                staticBootstrapChanged: report.staticBootstrapChanged,
                staticBootstrapPromptChars: report.staticBootstrapPromptChars,
                inferredTime: report.inferredTime || '',
                dominantEmotion: report.dominantEmotion || '',
                lastAuditedMessageId: clip(report.lastAuditedMessageId || '', 120),
