            const section = (worldState.sectionSummary && typeof worldState.sectionSummary === 'object')
                ? worldState.sectionSummary
                : null;
            if (!section) return false;
            const relationSignals = [];
            const relationCache = EntityManager.getRelationCache();
            for (const relation of relationCache.values()) {
                const left = String(relation?.entityA || '').trim();
                const right = String(relation?.entityB || '').trim();
                if (!left || !right) continue;
                if (mentionedNames.length > 0 && !mentionedNames.includes(left) && !mentionedNames.includes(right)) continue;
                const relationType = clip(relation?.relationType || '연결됨', 60);
                const tension = clamp(relation?.sentiments?.currentTension, 0, 1, 0);
                const trust = clamp(relation?.details?.trust, 0, 1, 0);
                relationSignals.push(`${left}↔${right} | ${relationType} | trust ${Math.round(trust * 100)}% | tension ${Math.round(tension * 100)}%`);
                if (relationSignals.length >= 8) break;
            }
            const nextSection = {
                ...section,
                entityContextHints: normalizeList([
                    ...mentionedNames.map(name => `focus:${name}`),
                    ...(Array.isArray(section.entityContextHints) ? section.entityContextHints : [])
                ], 8, 140),
                relationStateSignals: normalizeList([
                    ...relationSignals,
                    ...(Array.isArray(section.relationStateSignals) ? section.relationStateSignals : [])
                ], 8, 180),
                scenePressures: normalizeList([
                    inferredTime ? `scene_time:${inferredTime}` : '',
                    ...(Array.isArray(section.scenePressures) ? section.scenePressures : [])
                ], 8, 180)
            };
            const before = JSON.stringify(section);
            const after = JSON.stringify(nextSection);
