            const latestExcludedMessageId = String(classification?.latestExcludedMessageId || '').trim();
            const visibleWindowSignature = String(classification?.visibleWindowSignature || '').trim();
            if (!latestVisibleMessageId || !visibleWindowSignature) return false;
            const memoryAudit = MemoryState?.lastLiveAuditReport || {};
            const previous = String(memoryAudit?.lastAuditedMessageId || '').trim() ? memoryAudit : (fallbackAudit || {});
            return String(previous?.lastAuditedMessageId || '').trim() === latestVisibleMessageId
                && String(previous?.latestExcludedMessageId || '').trim() === latestExcludedMessageId
