                if (!raw) return;
                names.add(raw);
                names.add(raw.toLowerCase());
                try {
                    const normalized = EntityManager.normalizeName(raw, lorebook);
                    if (normalized) {
                        names.add(normalized);
                        names.add(String(normalized).toLowerCase());
                    }
                } catch {}
