            const relationPattern = /"entityA"\s*:\s*"([^"]{1,120})"/g;
            let relationMatch = null;
            const relationMatches = [];
            while ((relationMatch = relationPattern.exec(source))) {
                relationMatches.push({ entityA: decodeJsonishScalar(relationMatch[1]), index: relationMatch.index });
            }
