            quickControlPanel: typeof definition.quickControlPanel === 'function' ? definition.quickControlPanel : null,
            entityCardSection: typeof definition.entityCardSection === 'function' ? definition.entityCardSection : null,
            entityCreateSection: typeof definition.entityCreateSection === 'function' ? definition.entityCreateSection : null,
            relationCardSection: typeof definition.relationCardSection === 'function' ? definition.relationCardSection : null,
            entityCreateMutator: typeof definition.entityCreateMutator === 'function' ? definition.entityCreateMutator : null,
