            applyEntityRepairPatch: typeof definition.applyEntityRepairPatch === 'function' ? definition.applyEntityRepairPatch : null,
            relationRepairProvider: typeof definition.relationRepairProvider === 'function' ? definition.relationRepairProvider : null,
            applyRelationRepairPatch: typeof definition.applyRelationRepairPatch === 'function' ? definition.applyRelationRepairPatch : null,
            rebuildExtensionState: typeof definition.rebuildExtensionState === 'function' ? definition.rebuildExtensionState : null,
            onColdStart: typeof definition.onColdStart === 'function' ? definition.onColdStart : null,
            onReanalyze: typeof definition.onReanalyze === 'function' ? definition.onReanalyze : null,
