        const targetedPairs = buildTargetedReplayableTurnPairs(targetChat, locator, meta, {
            pairWindow: options?.pairWindow,
            allowFullFallback: options?.allowFullFallback !== false
        });
        if (targetedPairs.usedTargetedWindow) targeted += 1;
        if (targetedPairs.fullFallback) fallback += 1;
        if (targetedPairs.resolutionMode === 'message-id') messageIdMatches += 1;
        if (targetedPairs.resolutionMode === 'estimated-turn') estimatedTurnMatches += 1;
        const best = selectBestReplayableTurnForMemory(
            targetedPairs.replayableTurns,
            meta,
            rawContent,
            targetChat?.id || ''
        );
