        matched += 1;
        const nextTurn = Number(best.pair?.pairIndex || 0) + 1;
        const userTurnKey = buildLogicalUserTurnKey(best.pair?.userText || '', best.pair?.userText || '', false);
        const messageSignature = getMessageSignature(best.pair?.sourceMessage);
        const sourceMessageIds = normalizeCanonicalMessageIds(best.pairMessageIds);
