            sourceHash: String(best.pair?.sourceHash || meta?.sourceHash || '').trim(),
            sourceMessageIds,
            liveMessageIds: sourceMessageIds,
            m_id: getPrimaryCanonicalMessageId(sourceMessageIds, true),
            userTurnKey,
            messageSignature,
