                const entryTurn = Number(entry?.turn || 0);
                if (!entryTurn || usedTurns.has(entryTurn)) return false;
                const entryHash = String(TokenizerEngine.simpleHash(String(entry?.response || entry?.summary || '').trim()) || '').trim();
                return !!entryHash && entryHash === sourceHash;
