            setChecked("#sswi", c.sectionWorldInferenceEnabled !== false);
            const sectionRuntimeEnabled = normalizeSectionRuntimeEnabled(c.sectionRuntimeEnabled, true);
            setChecked("#ssec-model", sectionRuntimeEnabled.model !== false);
            setChecked("#ssec-submodel", sectionRuntimeEnabled.submodel !== false);
            setChecked("#ssec-otherax", sectionRuntimeEnabled.otherax !== false);
            setValue("#sfail", normalizeFailureMode(c.failureMode || 'soft'));
            setValue("#s-genre-hint", String(c.genreSoftHint || ''));
            applyInternalModulesToSettingsOverlay(overlay, c.internalModules);
            const interopModules = normalizeInteropModules(c.interopModules, c.internalModules);
            setChecked("#sio-gigatrans", interopModules.compatGigaTransInterop !== false);
            setChecked("#sio-lightboard", interopModules.compatLightboardInterop !== false);
            setChecked("#sio-illustration", interopModules.compatIllustrationInterop === true);
            const mrrpWrap = getEl("#smrrp-wrap");
            if (mrrpWrap) mrrpWrap.style.display = reasoningMode === 'custom' ? '' : 'none';
            const sibcWrap = getEl("#sibc-wrap");
            if (sibcWrap) sibcWrap.style.display = injectionPreset === 'custom' ? '' : 'none';

            setValue("#snsfwm", normalizeNsfwMode(c.nsfwMode || (c.nsfwEnabled ? 'direct' : 'off')));
            setValue("#sep", (c.embed && c.embed.provider) || "openai");
            setValue("#seu", (c.embed && c.embed.url) || "");
            setValue("#sek", (c.embed && c.embed.key) || "");
            setValue("#sem", (c.embed && c.embed.model) || "text-embedding-3-small");
            setValue("#seto", (c.embed && c.embed.timeout) || 30000);
            const memoryPreset = c.memoryPreset || inferMemoryPreset(c);
            setValue("#smp", MEMORY_PRESETS[memoryPreset] ? memoryPreset : "custom");
            setValue("#sml", c.knowledgeFilterLimit || c.maxLimit || RP_OPTIMIZED_MEMORY_PRESET.maxLimit);
            setValue("#sth", c.threshold || RP_OPTIMIZED_MEMORY_PRESET.threshold);
            const s = getEl("#sst");
            if (s) {
                s.value = c.simThreshold || RP_OPTIMIZED_MEMORY_PRESET.simThreshold;
                const sv = getEl("#sstv");
                if (sv) sv.textContent = parseFloat(s.value).toFixed(2);
            }
