const LIBRA_SubPluginCoordinator = (() => {
    const runtimeByPlugin = new Map();
    const patchProposals = [];
    const MAX_PATCH_PROPOSALS = 160;
    let proposalSequence = 0;
    let coordinatorMode = 'auto';
    const normalizeTextLite = (value) => {
        const text = String(value ?? '').trim();
        return text || '';
    };
    const cloneLite = (value) => {
        try {
            return JSON.parse(JSON.stringify(value ?? null));
        } catch (_) {
            if (Array.isArray(value)) return value.slice();
            if (value && typeof value === 'object') return { ...value };
            return value ?? null;
        }
    };
    const normalizePluginId = (pluginId) => normalizeTextLite(pluginId) || 'unknown';
    const getMode = () => coordinatorMode;
    const setMode = (nextMode) => {
        const normalizedMode = normalizeTextLite(nextMode).toLowerCase();
        coordinatorMode = normalizedMode === 'manual' ? 'manual' : 'auto';
        return coordinatorMode;
    };
    const sanitizeProposal = (proposal) => {
        const next = cloneLite(proposal) || {};
        delete next._commitAction;
        return next;
    };
    const reportRuntime = (pluginId, payload = {}) => {
        const normalizedPluginId = normalizePluginId(pluginId);
        const next = {
            pluginId: normalizedPluginId,
            reportedAt: Date.now(),
            ...(payload && typeof payload === 'object' ? cloneLite(payload) : {})
        };
        runtimeByPlugin.set(normalizedPluginId, next);
        return next;
    };
    const reportPatchProposal = (pluginId, payload = {}) => {
        const normalizedPluginId = normalizePluginId(pluginId);
        const rawPayload = payload && typeof payload === 'object' ? payload : {};
        const proposal = {
            proposalId: `coord-${Date.now()}-${++proposalSequence}`,
            pluginId: normalizedPluginId,
            reportedAt: Date.now(),
            status: 'pending',
            autoApply: rawPayload?.autoApply !== false,
            ...(cloneLite(rawPayload) || {})
        };
        if (typeof rawPayload?.commitAction === 'function') {
            proposal._commitAction = rawPayload.commitAction;
        }
        delete proposal.commitAction;
        patchProposals.push(proposal);
        while (patchProposals.length > MAX_PATCH_PROPOSALS) patchProposals.shift();
        return sanitizeProposal(proposal);
    };
    const listRuntime = () => Array.from(runtimeByPlugin.values()).map(cloneLite);
    const getRuntime = (pluginId) => cloneLite(runtimeByPlugin.get(normalizePluginId(pluginId)) || null);
    const listPatchProposals = (filters = {}) => {
        const pluginId = normalizeTextLite(filters?.pluginId);
        const entityName = normalizeTextLite(filters?.entityName);
        const domain = normalizeTextLite(filters?.domain);
        const status = normalizeTextLite(filters?.status);
        const limit = Number.isFinite(Number(filters?.limit)) ? Math.max(1, Math.min(120, Number(filters.limit))) : 40;
        return patchProposals
            .filter((entry) => {
                if (pluginId && entry?.pluginId !== pluginId) return false;
                if (domain && normalizeTextLite(entry?.domain) !== domain) return false;
                if (status && normalizeTextLite(entry?.status) !== status) return false;
                if (entityName) {
                    const names = Array.isArray(entry?.entityNames) ? entry.entityNames : [];
                    if (!names.some(name => normalizeTextLite(name) === entityName)) return false;
                }
                return true;
            })
            .slice(-limit)
            .map(sanitizeProposal);
    };
    const autoCommitPending = async (_context = {}, filters = {}) => {
        if (coordinatorMode !== 'auto') return [];
        const pluginId = normalizeTextLite(filters?.pluginId);
        const domain = normalizeTextLite(filters?.domain);
        const limit = Number.isFinite(Number(filters?.limit)) ? Math.max(1, Math.min(64, Number(filters.limit))) : 12;
        const pending = [];
        for (let idx = 0; idx < patchProposals.length; idx += 1) {
            const proposal = patchProposals[idx];
            if (!proposal || normalizeTextLite(proposal?.status) !== 'pending') continue;
            if (proposal?.autoApply === false) continue;
            if (pluginId && normalizeTextLite(proposal?.pluginId) !== pluginId) continue;
            if (domain && normalizeTextLite(proposal?.domain) !== domain) continue;
            pending.push(proposal);
            if (pending.length >= limit) break;
        }
        const results = [];
        for (const proposal of pending) {
            if (typeof proposal?._commitAction !== 'function') {
                proposal.status = 'skipped';
                proposal.commitNote = 'commit action not provided';
                proposal.appliedAt = Date.now();
                results.push(sanitizeProposal(proposal));
                continue;
            }
            proposal.status = 'applying';
            proposal.appliedAt = Date.now();
            try {
                const commitResult = await proposal._commitAction();
                proposal.status = 'applied';
                proposal.appliedAt = Date.now();
                proposal.commitResult = cloneLite(commitResult ?? true);
                delete proposal.error;
            } catch (error) {
                proposal.status = 'failed';
                proposal.appliedAt = Date.now();
                proposal.error = normalizeTextLite(error?.message || error) || 'commit failed';
            }
            results.push(sanitizeProposal(proposal));
        }
        return results;
    };
    const clearPlugin = (pluginId) => {
        const normalizedPluginId = normalizePluginId(pluginId);
        runtimeByPlugin.delete(normalizedPluginId);
        for (let idx = patchProposals.length - 1; idx >= 0; idx -= 1) {
            if (patchProposals[idx]?.pluginId === normalizedPluginId) patchProposals.splice(idx, 1);
        }
        return true;
    };
    const buildSnapshot = () => ({
        mode: coordinatorMode,
        runtime: listRuntime(),
        recentPatchProposals: listPatchProposals({ limit: 60 })
    });
    return Object.freeze({
        getMode,
        setMode,
        reportRuntime,
        reportPatchProposal,
        autoCommitPending,
        listRuntime,
        getRuntime,
        listPatchProposals,
        clearPlugin,
        buildSnapshot
    });
})();
const renderCoordinatorPanelHtml = (() => {
    const escHtml = (value) => String(value ?? '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
    const normalizePanelText = (value) => String(value ?? '')
        .replace(/\s+/g, ' ')
        .trim()
        .toLowerCase();
    const boolText = (value) => value === true ? '켜짐' : (value === false ? '꺼짐' : '-');
    const compactText = (value, max = 160) => {
        const text = String(value ?? '').replace(/\s+/g, ' ').trim();
        if (!text) return '';
        if (text.length <= max) return text;
        return `${text.slice(0, Math.max(0, max - 1)).trim()}…`;
    };
    const modeText = (value) => normalizePanelText(value) === 'manual' ? '수동 반영' : '자동 반영';
    const proposalStatusText = (value) => ({
        pending: '대기',
        applying: '적용 중',
        applied: '적용됨',
        failed: '실패',
        skipped: '건너뜀'
    }[normalizePanelText(value)] || '대기');
    const renderRuntimeCard = (entry = {}) => {
        const settings = entry?.settings && typeof entry.settings === 'object' ? entry.settings : {};
        const settingBits = [];
        if ('enabled' in settings) settingBits.push(`모듈 ${boolText(settings.enabled)}`);
        if ('promptInjectionEnabled' in settings) settingBits.push(`프롬프트 ${boolText(settings.promptInjectionEnabled)}`);
        if ('relationSyncEnabled' in settings) settingBits.push(`관계 동기화 ${boolText(settings.relationSyncEnabled)}`);
        if ('promptRecordMode' in settings) settingBits.push(`레코드 ${compactText(settings.promptRecordMode, 24)}`);
        return `
            <div style="margin-top:8px;padding:10px 11px;border:1px solid rgba(255,255,255,0.08);border-radius:12px;background:color-mix(in srgb,var(--bg2, #161c28) 84%, transparent)">
                <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start">
                    <div>
                        <strong style="color:var(--text, #e7f0ff)">${escHtml(entry?.pluginId || 'unknown')}</strong>
                        ${entry?.domain ? `<div style="margin-top:4px;font-size:11px;color:var(--text2, #9fb6d2)">도메인 · ${escHtml(entry.domain)}</div>` : ''}
                    </div>
                    ${entry?.phase ? `<span class="scope-inline-pill">${escHtml(entry.phase)}</span>` : ''}
                </div>
                ${entry?.lastStatus ? `<div style="margin-top:6px;font-size:12px;color:var(--text2, #9fb6d2)">${escHtml(entry.lastStatus)}</div>` : ''}
                <div style="margin-top:6px;font-size:11px;color:var(--text2, #9fb6d2)">
                    채팅 ${escHtml(entry?.activeChatId || 'global')}
                    ${Number.isFinite(Number(entry?.lastPromptEntityCount)) ? ` / 프롬프트 ${escHtml(entry.lastPromptEntityCount)}` : ''}
                    ${Number.isFinite(Number(entry?.changedCount)) ? ` / 변경 ${escHtml(entry.changedCount)}` : ''}
                    ${Number.isFinite(Number(entry?.lastChangedCount)) ? ` / 최근 변경 ${escHtml(entry.lastChangedCount)}` : ''}
                </div>
                ${settingBits.length ? `<div style="margin-top:6px;font-size:11px;color:var(--text2, #9fb6d2)">${escHtml(settingBits.join(' / '))}</div>` : ''}
            </div>
        `;
    };
    const renderProposalRow = (entry = {}) => `
        <div style="margin-top:8px;padding:9px 10px;border-radius:10px;background:color-mix(in srgb,var(--bg3, #1e2633) 82%, transparent)">
            <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start">
                <strong style="color:var(--text, #e7f0ff)">${escHtml(entry?.pluginId || 'unknown')}</strong>
                <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;justify-content:flex-end">
                    ${entry?.status ? `<span class="scope-inline-pill">${escHtml(proposalStatusText(entry.status))}</span>` : ''}
                    ${entry?.phase ? `<span style="font-size:11px;color:var(--text2, #9fb6d2)">${escHtml(entry.phase)}</span>` : ''}
                </div>
            </div>
            <div style="margin-top:4px;font-size:11px;color:var(--text2, #9fb6d2)">
                ${entry?.domain ? `도메인 ${escHtml(entry.domain)}` : ''}
                ${Number.isFinite(Number(entry?.changedCount)) ? ` / 변경 ${escHtml(entry.changedCount)}` : ''}
                ${entry?.activeChatId ? ` / 채팅 ${escHtml(entry.activeChatId)}` : ''}
            </div>
            ${Array.isArray(entry?.entityNames) && entry.entityNames.length ? `<div style="margin-top:4px;font-size:11px;color:var(--text2, #9fb6d2)">엔티티 · ${escHtml(entry.entityNames.slice(0, 6).join(', '))}</div>` : ''}
            ${entry?.source ? `<div style="margin-top:4px;font-size:11px;color:var(--text2, #9fb6d2)">출처 · ${escHtml(entry.source)}</div>` : ''}
            ${entry?.error ? `<div style="margin-top:4px;font-size:11px;color:#ffb4b4">오류 · ${escHtml(entry.error)}</div>` : ''}
        </div>
    `;
    return (snapshot = {}) => {
        const runtime = Array.isArray(snapshot?.runtime) ? snapshot.runtime : [];
        const proposals = Array.isArray(snapshot?.recentPatchProposals) ? snapshot.recentPatchProposals.slice(-12).reverse() : [];
        const runtimeHtml = runtime.length
            ? runtime.map(renderRuntimeCard).join('')
            : '<div class="scope-section-note" style="margin-top:8px">아직 보고된 서브플러그인 런타임 상태가 없습니다.</div>';
        const proposalHtml = proposals.length
            ? proposals.map(renderProposalRow).join('')
            : '<div class="scope-section-note" style="margin-top:8px">최근 제안 패치가 없습니다.</div>';
        return `
            <div class="scope-section-card" style="padding:12px 13px;border:1px solid rgba(255,255,255,0.08);border-radius:14px;background:
                radial-gradient(circle at top right, rgba(124,199,255,0.12), transparent 24%),
                linear-gradient(155deg,color-mix(in srgb,var(--bg2, #161c28) 90%, rgba(255,255,255,0.03)),color-mix(in srgb,var(--bg, #111622) 92%, rgba(255,196,122,0.05)))">
                <div style="font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:var(--text2, #9fb6d2)">SubPlugin Coordinator</div>
                <div style="margin-top:4px;font-size:16px;font-weight:800;color:var(--text, #e7f0ff)">서브플러그인 조율 상태</div>
                <div class="scope-section-note" style="margin-top:6px">본체가 받은 런타임 상태와 최근 패치 제안을 한곳에 보여줍니다. 현재 모드 · ${escHtml(modeText(snapshot?.mode))}</div>
                <div style="margin-top:12px;font-size:11px;font-weight:700;color:var(--text2, #9fb6d2)">런타임 상태</div>
                ${runtimeHtml}
                <div style="margin-top:12px;font-size:11px;font-weight:700;color:var(--text2, #9fb6d2)">최근 제안 패치</div>
                ${proposalHtml}
            </div>
        `;
    };
})();
